275 |     <script>
276 |         // DEBUG SYSTEM
277 |         let tapCount = 0;
278 |         const consoleEl = document.getElementById('debug-console');
279 |         function vlog(msg) {
280 |             const div = document.createElement('div');
281 |             div.className = 'log-entry';
282 |             div.innerText = `[${new Date().toLocaleTimeString().split(' ')[0]}] ${msg}`;
283 |             consoleEl.appendChild(div);
284 |             consoleEl.scrollTop = consoleEl.scrollHeight;
285 |         }
286 | 
287 |         function toggleDebug() {
288 |             tapCount++;
289 |             if (tapCount >= 5) {
290 |                 consoleEl.style.display = consoleEl.style.display === 'none' ? 'block' : 'none';
291 |                 vlog("--- Console Toggled ---");
292 |                 tapCount = 0;
293 |             }
294 |         }
295 | 
296 |         window.onerror = (m, s, l, c, e) => vlog(`ERR: ${m} at ${l}:${c}`);
297 |         console.log = (m) => vlog(`LOG: ${m}`);
298 |         // END DEBUG SYSTEM
299 | 
300 |         let allApps = [];
301 |         let dockPkgs = JSON.parse(localStorage.getItem('cortex_dock') || '["dialer", "messaging", "chrome", "telegram"]');
302 |         let homeShortcuts = JSON.parse(localStorage.getItem('cortex_home_grid') || '[]');
303 |         let startY = 0, startX = 0;
304 |         let longPressTimer = null;
305 |         let isLongPress = false;
306 | 
307 |         // Prevent OS native context menu from hijacking touch
308 |         window.addEventListener('contextmenu', e => e.preventDefault());
309 | 
310 |         function launchApp(pkg) {
311 |             if (isLongPress) return;
312 |             CortexLauncher.launch(pkg);
313 |         }
314 | 
315 |         function updateTime() {
316 |             const now = new Date();
317 |             document.getElementById('main-clock').innerText = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: true });
318 |             document.getElementById('main-date').innerText = now.toLocaleDateString([], { weekday: 'long', month: 'long', day: 'numeric' });
319 |         }
320 | 
321 |         function launchClock() {
322 |             const clockApp = allApps.find(a => a.pkg.toLowerCase().includes('clock') || a.pkg.toLowerCase().includes('deskclock'));
323 |             if (clockApp) CortexLauncher.launch(clockApp.pkg);
324 |         }
325 | 
326 |         function renderAll(appsList) {
327 |             // 1. Render Home Grid (Shortcuts above dock)
328 |             const homeGrid = document.getElementById('home-grid');
329 |             homeGrid.innerHTML = homeShortcuts.map(pkg => {
330 |                 const app = allApps.find(a => a.pkg === pkg);
331 |                 if (!app) return '';
332 |                 return `
333 |                     <div class="app-item" 
334 |                          onclick="CortexLauncher.launch('${app.pkg}')" 
335 |                          ontouchstart="handlePressStart(event, '${app.pkg}', false, true)" 
336 |                          ontouchend="handlePressEnd()" 
337 |                          ontouchcancel="handlePressEnd()" 
338 |                          ontouchmove="handlePressEnd()">
339 |                         <img class="app-icon" src="${app.icon}">
340 |                         <div class="app-label">${app.name}</div>
341 |                     </div>
342 |                 `;
343 |             }).join('');
344 | 
345 |             // 2. Render Dock
346 |             const dock = document.getElementById('main-dock');
347 |             dock.innerHTML = '';
348 |             const activeDockApps = [];
349 |             dockPkgs.forEach(pkg => {
350 |                 const match = allApps.find(a => a.pkg.toLowerCase().includes(pkg.toLowerCase()));
351 |                 if (match && !activeDockApps.find(d => d.pkg === match.pkg)) activeDockApps.push(match);
352 |             });
353 | 
354 |             dock.innerHTML = activeDockApps.slice(0, 4).map(app => `
355 |                 <div class="app-item" 
356 |                      onclick="CortexLauncher.launch('${app.pkg}')" 
357 |                      ontouchstart="handlePressStart(event, '${app.pkg}', true, false)" 
358 |                      ontouchend="handlePressEnd()" 
359 |                      ontouchcancel="handlePressEnd()" 
360 |                      ontouchmove="handlePressEnd()">
361 |                     <img class="app-icon" src="${app.icon}">
362 |                 </div>
363 |             `).join('');
364 | 
365 |             // Render Grid
366 |             const pager = document.getElementById('pager');
367 |             const dots = document.getElementById('dots');
368 |             pager.innerHTML = ''; dots.innerHTML = '';
369 | 
370 |             for (let i = 0; i < appsList.length; i += 24) {
371 |                 const chunk = appsList.slice(i, i + 24);
372 |                 const page = document.createElement('div');
373 |                 page.className = 'grid-page';
374 |                 page.innerHTML = chunk.map(app => `
375 |                     <div class="app-item" 
376 |                          onclick="CortexLauncher.launch('${app.pkg}')" 
377 |                          ontouchstart="handlePressStart(event, '${app.pkg}', false)" 
378 |                          ontouchend="handlePressEnd()" 
379 |                          ontouchcancel="handlePressEnd()" 
380 |                          ontouchmove="handlePressEnd()">
381 |                         <img class="app-icon" src="${app.icon}" loading="lazy">
382 |                         <div class="app-label">${app.name}</div>
383 |                     </div>
384 |                 `).join('');
385 |                 pager.appendChild(page);
386 |                 const dot = document.createElement('div');
387 |                 dot.className = 'dot' + (i === 0 ? ' active' : '');
388 |                 
389 |                 // Teleportation Logic
390 |                 const pageIdx = Math.floor(i / 24);
391 |                 dot.onclick = () => jumpToPage(pageIdx);
392 |                 
393 |                 dots.appendChild(dot);
394 |             }
395 |         }
396 | 
397 |         function jumpToPage(idx) {
398 |             const pager = document.getElementById('pager');
399 |             pager.scrollTo({
400 |                 left: idx * window.innerWidth,
401 |                 behavior: 'smooth'
402 |             });
403 |         }
404 | 
405 |         function handlePressStart(e, pkg, isDock, isHome) {
406 |             isLongPress = false;
407 |             longPressTimer = setTimeout(() => {
408 |                 isLongPress = true;
409 |                 showContextMenu(e.touches[0].clientX, e.touches[0].clientY, pkg, isDock, isHome);
410 |             }, 600);
411 |         }
412 | 
413 |         function handlePressEnd() {
414 |             clearTimeout(longPressTimer);
415 |         }
416 | 
417 |         function showContextMenu(x, y, pkg, isDock, isHome) {
418 |             vlog(`Showing Menu: ${pkg} at ${x},${y}`);
419 |             const menu = document.getElementById('context-menu');
420 |             const app = allApps.find(a => a.pkg === pkg);
421 |             if (!app) return;
422 | 
423 |             const menuWidth = 180;
424 |             const renderX = Math.min(x, window.innerWidth - menuWidth - 20);
425 |             const renderY = Math.min(y, window.innerHeight - 200);
426 | 
427 |             let html = `<div class="menu-item" onclick="CortexLauncher.openAppInfo('${pkg}')">ℹ️ App Info</div>`;
428 | 
429 |             if (isDock) {
430 |                 html += `<div class="menu-item danger" onclick="removeFromDock('${pkg}')">➖ Remove from Dock</div>`;
431 |             } else if (isHome) {
432 |                 html += `<div class="menu-item danger" onclick="removeFromHome('${pkg}')">➖ Remove from Home</div>`;
433 |             } else {
434 |                 html += `<div class="menu-item" onclick="addToHome('${pkg}')">➕ Add to Home</div>`;
435 |                 if (!app.isSystem) {
436 |                     html += `<div class="menu-item danger" onclick="CortexLauncher.requestUninstall('${pkg}')">🗑️ Uninstall</div>`;
437 |                 }
438 |             }
439 | 
440 |             menu.innerHTML = html;
441 |             menu.style.left = renderX + 'px';
442 |             menu.style.top = renderY + 'px';
443 |             menu.style.display = 'flex';
444 |         }
445 | 
446 |         function closeMenu() {
447 |             const menu = document.getElementById('context-menu');
448 |             if (menu.style.display !== 'none') {
449 |                 vlog('Closing Menu');
450 |                 menu.style.display = 'none';
451 |             }
452 |         }
453 | 
454 |         function addToHome(pkg) {
455 |             // If dock has room, put it there. Otherwise, put it in the home grid.
456 |             if (dockPkgs.length < 4 && !dockPkgs.includes(pkg)) {
457 |                 dockPkgs.push(pkg);
458 |                 localStorage.setItem('cortex_dock', JSON.stringify(dockPkgs));
459 |             } else if (!homeShortcuts.includes(pkg) && !dockPkgs.includes(pkg)) {
460 |                 homeShortcuts.push(pkg);
461 |                 localStorage.setItem('cortex_home_grid', JSON.stringify(homeShortcuts));
462 |             }
463 |             renderAll(allApps);
464 |             closeMenu();
465 |         }
466 | 
467 |         function removeFromHome(pkg) {
468 |             homeShortcuts = homeShortcuts.filter(p => p !== pkg);
469 |             localStorage.setItem('cortex_home_grid', JSON.stringify(homeShortcuts));
470 |             renderAll(allApps);
471 |             closeMenu();
472 |         }
473 | 
474 |         function removeFromDock(pkg) {
475 |             dockPkgs = dockPkgs.filter(p => p !== pkg);
476 |             localStorage.setItem('cortex_dock', JSON.stringify(dockPkgs));
477 |             renderAll(allApps);
478 |             closeMenu();
479 |         }
480 | 
481 |         function updateDots() {
482 |             closeMenu();
483 |             const pager = document.getElementById('pager');
484 |             const dots = document.querySelectorAll('.dot');
485 |             const idx = Math.round(pager.scrollLeft / window.innerWidth);
486 |             dots.forEach((d, i) => d.classList.toggle('active', i === idx));
487 |         }
488 | 
489 |         function handleSearch() {
490 |             const query = document.getElementById('search-input').value.toLowerCase();
491 |             renderAll(allApps.filter(a => a.name.toLowerCase().includes(query)));
492 |         }
493 | 
494 |         // GESTURE ENGINE
495 |         window.addEventListener('touchstart', e => { 
496 |             startY = e.touches[0].clientY; 
497 |             startX = e.touches[0].clientX;
498 |         });
499 | 
500 |         window.addEventListener('touchmove', e => {
501 |             const moveX = Math.abs(e.touches[0].clientX - startX);
502 |             const moveY = Math.abs(e.touches[0].clientY - startY);
503 |             // If user moves more than 10px, they are swiping, not long-pressing
504 |             if (moveX > 10 || moveY > 10) {
505 |                 closeMenu();
506 |             }
507 |         });
508 | 
509 |         window.addEventListener('touchend', e => {
510 |             const endY = e.changedTouches[0].clientY;
511 |             const diff = startY - endY;
512 |             const isActive = document.body.classList.contains('drawer-active');
513 | 
514 |             // diff > 50: Swiped UP
515 |             // diff < -50: Swiped DOWN
516 |             if (!isActive && diff > 50) {
517 |                 document.body.classList.add('drawer-active');
518 |             } else if (isActive && diff < -50) {
519 |                 // Only close if swiping DOWN while in drawer
520 |                 document.body.classList.remove('drawer-active');
521 |             }
522 |         });
523 | 
524 |         window.showHomeScreen = () => {
525 |             document.body.classList.remove('drawer-active');
526 |             closeMenu();
527 |         };
528 | 
529 |         window.handleBack = () => {
530 |             // 1. Close context menu if open
531 |             const menu = document.getElementById('context-menu');
532 |             if (menu && menu.style.display === 'flex') {
533 |                 closeMenu();
534 |                 return true;
535 |             }
536 |             // 2. Close app drawer if open
537 |             if (document.body.classList.contains('drawer-active')) {
538 |                 showHomeScreen();
539 |                 return true;
540 |             }
541 |             // 3. Already at home
542 |             return false;
543 |         };
544 | 
545 |         window.onload = () => {
546 |             try {
547 |                 const raw = CortexLauncher.getAppList();
548 |                 allApps = JSON.parse(raw).sort((a,b) => a.name.localeCompare(b.name));
549 |                 renderAll(allApps);
550 |                 setInterval(updateTime, 1000); updateTime();
551 |             } catch (e) { }
552 |         };
553 |     </script>
554 | </body>
555 | </html>
