function renderAll(appsList) {
    const homeScreen = document.getElementById('home-screen');
    homeScreen.innerHTML = '';

    const activeDockApps = [];
    dockPkgs.forEach(pkg => {
        const match = allApps.find(a => a.pkg.toLowerCase().includes(pkg.toLowerCase()));
        if (match && !activeDockApps.find(d => d.pkg === match.pkg)) activeDockApps.push(match);
    });
    const dockHtml = activeDockApps.slice(0, 4).map(app => `
        <div class="app-item" onclick="!isEditorActive() && CortexLauncher.launch('${app.pkg}')" ontouchstart="handlePressStart(event, '${app.pkg}', true, false)" ontouchend="handlePressEnd()" ontouchcancel="handlePressEnd()">
            <img class="app-icon" src="${app.icon}">
        </div>`).join('');

    const isEditing = isEditorActive();

    homePages.forEach((pageShortcuts, pageIdx) => {
        const page = document.createElement('div');
        page.className = 'home-page';

        const gridHtml = pageShortcuts.map(pkg => {
            const app = allApps.find(a => a.pkg === pkg);
            if (!app) return '';
            return `
                <div class="app-item" onclick="!isEditorActive() && CortexLauncher.launch('${app.pkg}')" ontouchstart="handlePressStart(event, '${app.pkg}', false, true)" ontouchend="handlePressEnd()" ontouchcancel="handlePressEnd()">
                    <img class="app-icon" src="${app.icon}">
                    <div class="app-label">${app.name}</div>
                </div>`;
        }).join('');

        page.innerHTML = `
            <div class="trash-header" onclick="removeHomePage(${pageIdx})"><div class="trash-icon"></div><div class="editor-divider"></div></div>
            <div class="home-content" onclick="launchClock()">
                <div id="main-clock">${document.getElementById('main-clock')?.innerText || '00:00'}</div>
                <div id="main-date">${document.getElementById('main-date')?.innerText || '...'}</div>
            </div>
            <div class="home-grid">${gridHtml}</div>
            <div class="dock">${dockHtml}</div>
        `;
        homeScreen.appendChild(page);
    });

    // Append the "Add Screen" card if in editor mode
    if (isEditing) {
        const addPage = document.createElement('div');
        addPage.className = 'home-page';
        addPage.innerHTML = `
            <div class="add-page-container">
                <div class="add-page-circle" onclick="addHomePage(); event.stopPropagation();">
                    <div class="add-page-plus">+</div>
                </div>
            </div>
        `;
        homeScreen.appendChild(addPage);
    }

