function handleGlobalClick(e) {
    // 1. Close context menu if open
    closeMenu();

    // 2. Handle Editor Mode dismissal
    if (isEditorActive()) {
        // Don't close if we clicked the 'Trash', '+' buttons, or the add-page card
        if (e.target.closest('.trash-header') || e.target.closest('.editor-symbol') || e.target.closest('.add-page-circle')) {
            return;
        }
        document.body.classList.remove('editor-active');
        e.stopPropagation();
    }
}

